{
var seed = GetInt(parameters, "seed", context.Seed);
var scale = GetFloat(parameters, "scale", 2f);
var flowSpeed = GetFloat(parameters, "flowSpeed", 0.5f);
var flowAngle = GetFloat(parameters, "flowAngle", 0f);
var waveStrength = GetFloat(parameters, "waveStrength", 0.5f);
var foamAmount = GetFloat(parameters, "foamAmount", 0.3f);
var deepColor = GetColor(parameters, "deepColor", Color.FromRgb(10, 40, 100));
var shallowColor = GetColor(parameters, "shallowColor", Color.FromRgb(50, 120, 200));
var foamColor = GetColor(parameters, "foamColor", Color.FromRgb(240, 250, 255));
var rippleStrength = GetFloat(parameters, "rippleStrength", 0.3f);
var opacity = GetFloat(parameters, "opacity", 0.8f);
var octaves = Math.Max(1, GetInt(parameters, "octaves", 3));
var invert = GetBool(parameters, "invert", false);

var size = context.TileSize;
var buffer = new PixelBuffer(size, size);

var dR = deepColor.R / 255f; var dG = deepColor.G / 255f; var dB = deepColor.B / 255f;
var sR = shallowColor.R / 255f; var sG = shallowColor.G / 255f; var sB = shallowColor.B / 255f;
var fR = foamColor.R / 255f; var fG = foamColor.G / 255f; var fB = foamColor.B / 255f;

var angleRad = flowAngle * MathF.PI / 180f;
var cosAngle = MathF.Cos(angleRad);
var sinAngle = MathF.Sin(angleRad);

var period = Math.Max(1, (int)MathF.Round(scale * 2f));

buffer.ParallelForEachPixel((x, y) =>
{
    var u = (x + 0.5f) / size;
    var v = (y + 0.5f) / size;

    // --- Flow noise: directional distortion ---
    // Rotate coordinates to align with flow direction
    var flowU = u * cosAngle - v * sinAngle;
    var flowV = u * sinAngle + v * cosAngle;

    // Primary flow noise (stretched along flow direction)
    var flowNoise = TileableFractalNoise(
        flowU * scale * 0.5f, flowV * scale * 2f,
        period, octaves, 0.55f, 2.2f, seed);

    // Secondary noise for cross-flow variation
    var crossNoise = TileableFractalNoise(
        u * scale * 0.8f + 50f, v * scale * 0.8f + 50f,
        period, octaves - 1, 0.5f, 2f, seed + 100);

    // --- Wave height map ---
    var wave = TileableFractalNoise(
        u * scale * 1.5f, v * scale * 1.5f,
        period, octaves, 0.5f, 2.2f, seed + 200);

    // Flow perturbs the wave
    var flowOffset = (flowNoise - 0.5f) * flowSpeed * 0.3f;
    wave += flowOffset;
    wave = Math.Clamp(wave, 0f, 1f);

    // --- Ripple detail (high-frequency) ---
    var ripple = 0f;
    if (rippleStrength > 0f)
    {
        var ripplePhase = u * scale * 6f + v * scale * 4f + crossNoise * 2f;
        ripple = MathF.Sin(ripplePhase * MathF.PI * 2f) * rippleStrength * 0.1f;
        // Secondary ripple at different frequency
        ripple += MathF.Sin((u * scale * 4f - v * scale * 5f) * MathF.PI * 2f + seed) * rippleStrength * 0.06f;
    }

    // --- Depth coloring ---
    // Deep areas (low wave) → dark blue, Shallow (high wave) → light blue
    var depth = wave * waveStrength + 0.3f;
    depth = Math.Clamp(depth, 0f, 1f);

    var waterR = Lerp(dR, sR, depth);
    var waterG = Lerp(dG, sG, depth);
    var waterB = Lerp(dB, sB, depth);

    // Add ripple to surface
    waterR += ripple;
    waterG += ripple * 0.8f;
    waterB += ripple * 1.2f;

    // --- Foam detection ---
    // Foam forms where wave amplitude crosses a threshold (wave crests)
    var foamThreshold = 1f - foamAmount * 0.5f;

    // Use the gradient of the wave field to find crests
    var waveDX = TileableFractalNoise(
        (u + 0.02f) * scale * 1.5f, v * scale * 1.5f,
        period, 2, 0.5f, 2f, seed + 300);
    var waveGradient = MathF.Abs(waveDX - wave);

    var foamSignal = waveGradient * 4f * foamAmount;
    foamSignal = Math.Clamp(foamSignal, 0f, 1f);

    // Foam also appears at wave crests
    var crestFoam = MathF.Max(0f, (wave - foamThreshold) / (1f - foamThreshold));
    crestFoam = crestFoam * crestFoam * foamAmount;
    foamSignal = MathF.Max(foamSignal, crestFoam);

    // Break up foam with fine noise for organic look
    var foamDetail = TileableFractalNoise(
        u * scale * 8f, v * scale * 8f,
        Math.Max(1, period / 2), 1, 0.5f, 2f, seed + 400);
    foamSignal *= foamDetail > 0.3f ? 1f : foamDetail * 3f;
    foamSignal = Math.Clamp(foamSignal, 0f, 1f);

    // --- Compose final color ---
    var foamBlend = foamSignal;
    var finalR = Lerp(waterR, fR, foamBlend);
    var finalG = Lerp(waterG, fG, foamBlend);
    var finalB = Lerp(waterB, fB, foamBlend);
    var finalA = opacity;

    // Specular highlight on wave crests
    var spec = MathF.Pow(MathF.Max(0f, wave * 2f - 1f), 4f) * 0.3f;
    finalR = Math.Clamp(finalR + spec, 0f, 1f);
    finalG = Math.Clamp(finalG + spec, 0f, 1f);
    finalB = Math.Clamp(finalB + spec * 1.2f, 0f, 1f);

    if (invert) { finalR = 1f - finalR; finalG = 1f - finalG; finalB = 1f - finalB; }

    buffer.SetPixel(x, y, finalR, finalG, finalB, finalA);
});

return buffer;
}
